import React, { useEffect, useMemo, useRef, useState } from "react";
import Navbar from "./Components/Navbar";
import AboutSection from "./Sections/AboutSection";
import ContactSection from "./Sections/ContactSection";
import ExperienceSection from "./Sections/ExperienceSection";
import Footer from "./Sections/Footer";
import HeaderSection from "./Sections/HeaderSection";
import ProjectsSection from "./Sections/ProjectsSection";
import SkillsSection from "./Sections/SkillsSection";

function App() {
  const [activeLink, setActiveLink] = useState("home");

  const updateActiveLink = (link: string) => {
    setActiveLink(link);
  };

  const refHome = useRef(null);
  const refAbout = useRef(null);
  const refProjects = useRef(null);
  const refSkills = useRef(null);
  const refExp = useRef(null);
  const refContact = useRef(null);

  const isInViewportHome = useIsInViewport(refHome);
  const isInViewportAbout = useIsInViewport(refAbout);
  const isInViewportProjects = useIsInViewport(refProjects);
  const isInViewportSkills = useIsInViewport(refSkills);
  const isInViewportExp = useIsInViewport(refExp);
  const isInViewportContact = useIsInViewport(refContact);

  useEffect(() => {
    if (isInViewportHome) {
      setActiveLink("home");
    }
  }, [isInViewportHome]);

  useEffect(() => {
    if (isInViewportAbout) {
      setActiveLink("about");
    }
  }, [isInViewportAbout]);

  useEffect(() => {
    if (isInViewportProjects) {
      setActiveLink("projects");
    }
  }, [isInViewportProjects]);

  useEffect(() => {
    if (isInViewportSkills) {
      setActiveLink("skills");
    }
  }, [isInViewportSkills]);

  useEffect(() => {
    if (isInViewportExp) {
      setActiveLink("work");
    }
  }, [isInViewportExp]);

  useEffect(() => {
    if (isInViewportContact) {
      setActiveLink("contact");
    }
  }, [isInViewportContact]);

  //swiper JS
  return (
    <div className="app">
      <Navbar active={activeLink} update={updateActiveLink} />
      <div ref={refHome}>
        <HeaderSection />
      </div>
      <div ref={refAbout}>
        <AboutSection />
      </div>
      <div ref={refProjects}>
        <ProjectsSection />
      </div>
      <div ref={refProjects}>
        <SkillsSection />
      </div>
      <div ref={refExp}>
        <ExperienceSection />
      </div>
      <div ref={refContact}>
        <ContactSection />
      </div>
      <Footer />
    </div>
  );

  function useIsInViewport(ref: any) {
    const [isIntersecting, setIsIntersecting] = useState(false);

    const observer = useMemo(
      () =>
        new IntersectionObserver(([entry]) =>
          setIsIntersecting(entry.isIntersecting)
        ),
      []
    );

    useEffect(() => {
      observer.observe(ref.current);

      return () => {
        observer.disconnect();
      };
    }, [ref, observer]);

    return isIntersecting;
  }
}

export default App;
